/**
 * CSV Parser Library
 * A comprehensive TypeScript CSV parser with type coercion, error handling, and aggregation methods
 */

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface ParseError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: ParseError[];
  filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<string | null, Array<Record<string, any>>>;
}

/**
 * Coerce a string value to its appropriate type
 * - "null", "NULL", or empty string → null
 * - "true" or "false" (case-insensitive) → boolean
 * - Numeric strings → number
 * - Everything else → string
 */
function coerceValue(value: string): any {
  // Handle null values
  if (value === "null" || value === "NULL" || value === "") {
    return null;
  }

  // Handle booleans
  if (value.toLowerCase() === "true") {
    return true;
  }
  if (value.toLowerCase() === "false") {
    return false;
  }

  // Handle numbers
  const trimmed = value.trim();
  if (!isNaN(Number(trimmed)) && trimmed !== "") {
    return Number(trimmed);
  }

  // Default to string
  return value;
}

/**
 * Parse a single CSV line into fields, handling quotes and escaping
 */
function parseCSVLine(
  line: string,
  delimiter: string = ",",
  quote: string = '"'
): { fields: string[]; error?: string } {
  const fields: string[] = [];
  let currentField = "";
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    if (char === quote) {
      if (inQuotes && nextChar === quote) {
        // Escaped quote (two quotes = one literal quote)
        currentField += quote;
        i += 2;
      } else {
        // Toggle quoted state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // Field delimiter found (not inside quotes)
      fields.push(currentField);
      currentField = "";
      i++;
    } else {
      // Regular character
      currentField += char;
      i++;
    }
  }

  // Add the last field
  fields.push(currentField);

  // Check for unclosed quotes
  if (inQuotes) {
    return { fields: [], error: "Unclosed quote in CSV line" };
  }

  return { fields };
}

/**
 * Create a CSVResult object with all methods
 */
function createCSVResult(
  rows: Array<Record<string, any>>,
  headers: string[],
  errors: ParseError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, any>, index: number) => boolean): CSVResult {
      const filtered = rows.filter(predicate);
      return createCSVResult(filtered, headers, errors);
    },

    sum(column: string): number {
      let sum = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          sum += value;
        }
      }
      return sum;
    },

    average(column: string): number {
      let sum = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          sum += value;
          count++;
        }
      }
      return count === 0 ? 0 : sum / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<string | null, Array<Record<string, any>>> {
      const groups = new Map<string | null, Array<Record<string, any>>>();
      for (const row of rows) {
        const value = row[column];
        const key = value === null ? null : String(value);
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key)!.push(row);
      }
      return groups;
    },
  };
}

/**
 * Parse CSV content into structured data
 * @param input CSV string to parse
 * @param options Parsing options (delimiter, quote character, line separator)
 * @returns CSVResult with parsed data, headers, errors, and aggregation methods
 */
export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";

  const errors: ParseError[] = [];
  const rows: Array<Record<string, any>> = [];

  // Split input into lines
  const lines = input.split(lineSeparator);

  // Handle empty input
  if (lines.length === 0 || (lines.length === 1 && lines[0].trim() === "")) {
    return createCSVResult([], [], []);
  }

  // Parse header line
  const headerResult = parseCSVLine(lines[0], delimiter, quote);
  if (headerResult.error) {
    errors.push({ row: 0, message: headerResult.error });
    return createCSVResult([], [], errors);
  }

  const headers = headerResult.fields.map((h) => h.trim());

  // Parse data rows
  for (let rowIndex = 1; rowIndex < lines.length; rowIndex++) {
    const line = lines[rowIndex];

    // Skip empty lines
    if (line.trim() === "") {
      continue;
    }

    const result = parseCSVLine(line, delimiter, quote);

    if (result.error) {
      errors.push({ row: rowIndex, message: result.error });
      continue;
    }

    const fields = result.fields;

    // Validate field count
    if (fields.length !== headers.length) {
      errors.push({
        row: rowIndex,
        message: `Field count mismatch: expected ${headers.length}, got ${fields.length}`,
      });
      continue;
    }

    // Create row object with type coercion
    const row: Record<string, any> = {};
    for (let fieldIndex = 0; fieldIndex < headers.length; fieldIndex++) {
      const value = fields[fieldIndex].trim();
      row[headers[fieldIndex]] = coerceValue(value);
    }

    rows.push(row);
  }

  return createCSVResult(rows, headers, errors);
}

/**
 * Comprehensive Test Suite for CSV Parser
 * Uses simple assertions without a test framework
 */

import { parseCSV } from "./csv-parser";

// ============================================================================
// Assertion Utilities
// ============================================================================

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`❌ Assertion Failed: ${message}`);
  }
}

function assertEquals<T>(actual: T, expected: T, message: string): void {
  if (JSON.stringify(actual) !== JSON.stringify(expected)) {
    throw new Error(
      `❌ Assertion Failed: ${message}\n  Expected: ${JSON.stringify(expected)}\n  Actual: ${JSON.stringify(actual)}`
    );
  }
}

function assertArrayEquals<T>(actual: T[], expected: T[], message: string): void {
  if (actual.length !== expected.length) {
    throw new Error(
      `❌ Array length mismatch: ${message}\n  Expected length: ${expected.length}\n  Actual length: ${actual.length}`
    );
  }
  for (let i = 0; i < actual.length; i++) {
    if (JSON.stringify(actual[i]) !== JSON.stringify(expected[i])) {
      throw new Error(
        `❌ Array element mismatch at index ${i}: ${message}\n  Expected: ${JSON.stringify(expected[i])}\n  Actual: ${JSON.stringify(actual[i])}`
      );
    }
  }
}

function assertObjectEquals(actual: any, expected: any, message: string): void {
  const actualStr = JSON.stringify(actual, Object.keys(expected).sort());
  const expectedStr = JSON.stringify(expected, Object.keys(expected).sort());
  if (actualStr !== expectedStr) {
    throw new Error(
      `❌ Object mismatch: ${message}\n  Expected: ${expectedStr}\n  Actual: ${actualStr}`
    );
  }
}

function runTest(name: string, fn: () => void): void {
  try {
    fn();
    console.log(`✓ ${name}`);
  } catch (error) {
    console.error(error);
    process.exit(1);
  }
}

// ============================================================================
// TEST SUITE
// ============================================================================

// --- Basic Parsing ---

runTest("Basic parsing - simple CSV with headers and rows", () => {
  const csv = `name,age,city
John,30,NYC
Jane,25,LA`;
  const result = parseCSV(csv);

  assertArrayEquals(result.headers, ["name", "age", "city"], "Headers should match");
  assertEquals(result.rows.length, 2, "Should have 2 rows");
  assertObjectEquals(result.rows[0], { name: "John", age: 30, city: "NYC" }, "First row");
  assertObjectEquals(result.rows[1], { name: "Jane", age: 25, city: "LA" }, "Second row");
  assertEquals(result.errors.length, 0, "No errors should occur");
});

runTest("Basic parsing - single field per line", () => {
  const csv = `id
1
2
3`;
  const result = parseCSV(csv);

  assertArrayEquals(result.headers, ["id"], "Should have single header");
  assertEquals(result.rows.length, 3, "Should have 3 rows");
  assertEquals(result.rows[0].id, 1, "First row id");
  assertEquals(result.rows[1].id, 2, "Second row id");
  assertEquals(result.rows[2].id, 3, "Third row id");
});

// --- Quoted Fields ---

runTest("Quoted fields - commas inside quoted fields", () => {
  const csv = `name,address
John,"123 Main St, Apt 4"
Jane,"456 Oak Ave, Suite 200"`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].address, "123 Main St, Apt 4", "Address with comma");
  assertEquals(result.rows[1].address, "456 Oak Ave, Suite 200", "Address with comma");
});

runTest("Quoted fields - multiple quoted fields in one row", () => {
  const csv = `first,second,third
"a,b","c,d","e,f"`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].first, "a,b", "First quoted field");
  assertEquals(result.rows[0].second, "c,d", "Second quoted field");
  assertEquals(result.rows[0].third, "e,f", "Third quoted field");
});

runTest("Quoted fields - quoted field with delimiters at boundaries", () => {
  const csv = `text
"hello, world, test"`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].text, "hello, world, test", "Quoted field with multiple commas");
});

// --- Escaped Quotes ---

runTest("Escaped quotes - double quotes within quoted fields", () => {
  const csv = `text
"He said ""Hello"""
"She replied ""Hi there"""`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].text, 'He said "Hello"', "Escaped quotes converted to single quote");
  assertEquals(result.rows[1].text, 'She replied "Hi there"', "Escaped quotes converted");
});

runTest("Escaped quotes - multiple escaped quotes in one field", () => {
  const csv = `message
"I said ""yes"", he said ""no"", she said ""maybe"""`;
  const result = parseCSV(csv);

  assertEquals(
    result.rows[0].message,
    'I said "yes", he said "no", she said "maybe"',
    "Multiple escaped quotes"
  );
});

runTest("Escaped quotes - escaped quote at start and end", () => {
  const csv = `text
"""quoted text"""`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].text, '"quoted text"', "Quotes at boundaries");
});

// --- Custom Delimiters ---

runTest("Custom delimiter - tab separated values", () => {
  const csv = `name\tage\tcity
John\t30\tNYC
Jane\t25\tLA`;
  const result = parseCSV(csv, { delimiter: "\t" });

  assertArrayEquals(result.headers, ["name", "age", "city"], "Headers with tab delimiter");
  assertEquals(result.rows.length, 2, "Correct row count");
  assertEquals(result.rows[0].name, "John", "First row name");
});

runTest("Custom delimiter - semicolon separated", () => {
  const csv = `id;product;price
1;Apple;2.50
2;Banana;1.20`;
  const result = parseCSV(csv, { delimiter: ";" });

  assertArrayEquals(result.headers, ["id", "product", "price"], "Headers with semicolon");
  assertEquals(result.rows[0].product, "Apple", "Product field");
});

runTest("Custom delimiter - pipe separated", () => {
  const csv = `name|role
Alice|Manager
Bob|Developer`;
  const result = parseCSV(csv, { delimiter: "|" });

  assertEquals(result.rows[0].role, "Manager", "Role with pipe delimiter");
});

runTest("Custom quote character - single quotes", () => {
  const csv = `text
'He said "Hello"'
'She said "Hi"'`;
  const result = parseCSV(csv, { quote: "'" });

  assertEquals(result.rows[0].text, 'He said "Hello"', "Single quote as quote char");
});

runTest("Custom line separator - CRLF line endings", () => {
  const csv = `name,age\r\nJohn,30\r\nJane,25`;
  const result = parseCSV(csv, { lineSeparator: "\r\n" });

  assertEquals(result.rows.length, 2, "Correct row count with CRLF");
  assertEquals(result.rows[0].name, "John", "First row with CRLF");
  assertEquals(result.rows[1].name, "Jane", "Second row with CRLF");
});

runTest("Custom delimiter and quote - semicolon with single quotes", () => {
  const csv = `name;address
John;'123 Main; St'
Jane;'456 Oak; Ave'`;
  const result = parseCSV(csv, { delimiter: ";", quote: "'" });

  assertEquals(result.rows[0].address, "123 Main; St", "Semicolon inside single quotes");
});

// --- Type Coercion ---

runTest("Type coercion - integers", () => {
  const csv = `id,name
1,John
2,Jane
100,Bob`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].id, 1, "First id as number");
  assertEquals(typeof result.rows[0].id, "number", "ID is number type");
  assertEquals(result.rows[2].id, 100, "Large integer");
});

runTest("Type coercion - floating point numbers", () => {
  const csv = `price
19.99
15.50
100.0`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].price, 19.99, "Float value");
  assertEquals(typeof result.rows[0].price, "number", "Price is number type");
  assertEquals(result.rows[2].price, 100, "Whole float");
});

runTest("Type coercion - negative numbers", () => {
  const csv = `temperature
-5.5
0
25.3`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].temperature, -5.5, "Negative float");
  assertEquals(result.rows[1].temperature, 0, "Zero");
  assertEquals(result.rows[2].temperature, 25.3, "Positive float");
});

runTest("Type coercion - boolean true", () => {
  const csv = `active
true
True
TRUE`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, true, "Lowercase 'true'");
  assertEquals(result.rows[1].active, true, "Mixed case 'True'");
  assertEquals(result.rows[2].active, true, "Uppercase 'TRUE'");
  assertEquals(typeof result.rows[0].active, "boolean", "Boolean type");
});

runTest("Type coercion - boolean false", () => {
  const csv = `active
false
False
FALSE`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].active, false, "Lowercase 'false'");
  assertEquals(result.rows[1].active, false, "Mixed case 'False'");
  assertEquals(result.rows[2].active, false, "Uppercase 'FALSE'");
});

runTest("Type coercion - null keyword", () => {
  const csv = `value
null
NULL`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, null, "Lowercase 'null'");
  assertEquals(result.rows[1].value, null, "Uppercase 'NULL'");
});

runTest("Type coercion - empty string to null", () => {
  const csv = `value
""
text`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].value, null, "Empty quoted string becomes null");
  assertEquals(result.rows[1].value, "text", "Non-empty stays string");
});

runTest("Type coercion - mixed types in column", () => {
  const csv = `data
123
45.67
text
true
false
null`;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].data, 123, "Integer");
  assertEquals(result.rows[1].data, 45.67, "Float");
  assertEquals(result.rows[2].data, "text", "String");
  assertEquals(result.rows[3].data, true, "Boolean true");
  assertEquals(result.rows[4].data, false, "Boolean false");
  assertEquals(result.rows[5].data, null, "Null value");
});

runTest("Type coercion - whitespace is trimmed before coercion", () => {
  const csv = `number,text
  123  ,  hello  
  45.67  ,  world  `;
  const result = parseCSV(csv);

  assertEquals(result.rows[0].number, 123, "Number with spaces trimmed");
  assertEquals(result.rows[0].text, "hello", "Text with spaces trimmed");
  assertEquals(result.rows[1].number, 45.67, "Float with spaces");
});

// --- Error Handling ---

runTest("Error handling - unclosed quote", () => {
  const csv = `name,value
"John Doe,100`;
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 1, "Should have 1 error");
  assertEquals(result.errors[0].row, 1, "Error on row 1");
  assert(result.errors[0].message.includes("quote"), "Error mentions quote");
  assertEquals(result.rows.length, 0, "No rows parsed");
});

runTest("Error handling - field count mismatch", () => {
  const csv = `name,age,city
John,30
Jane,25,LA,Extra`;
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 2, "Should have 2 errors");
  assertEquals(result.rows.length, 0, "No valid rows");
});

runTest("Error handling - multiple errors collected", () => {
  const csv = `a,b,c
1,2
"unclosed,3,4
5,6,7,8`;
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 3, "Should collect all 3 errors");
  assertEquals(result.rows.length, 0, "No rows when all have errors");
});

runTest("Error handling - some rows valid, some invalid", () => {
  const csv = `name,value
John,100
"Bad,200
Jane,300`;
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 1, "One malformed row");
  assertEquals(result.rows.length, 2, "Two valid rows");
  assertEquals(result.rows[0].name, "John", "First valid row");
  assertEquals(result.rows[1].name, "Jane", "Second valid row");
});

runTest("Error handling - correct error row numbers", () => {
  const csv = `col
valid
"bad
valid
"another bad`;
  const result = parseCSV(csv);

  assertEquals(result.errors.length, 2, "Two errors");
  assertEquals(result.errors[0].row, 2, "First error on row 2");
  assertEquals(result.errors[1].row, 4, "Second error on row 4");
});

// --- Filtering ---

runTest("Filter - basic single filter", () => {
  const csv = `name,age,city
John,30,NYC
Jane,25,LA
Bob,35,NYC`;
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.age > 25);
  assertEquals(filtered.rows.length, 2, "Should have 2 rows after filter");
  assertEquals(filtered.rows[0].name, "John", "John matches filter");
  assertEquals(filtered.rows[1].name, "Bob", "Bob matches filter");
});

runTest("Filter - filter with string comparison", () => {
  const csv = `name,city
John,NYC
Jane,LA
Bob,NYC`;
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.city === "NYC");
  assertEquals(filtered.rows.length, 2, "NYC residents");
  assertEquals(filtered.rows[0].name, "John", "First NYC person");
  assertEquals(filtered.rows[1].name, "Bob", "Second NYC person");
});

runTest("Filter - chained filters", () => {
  const csv = `name,age,city
John,30,NYC
Jane,25,LA
Bob,35,NYC
Alice,28,NYC`;
  const result = parseCSV(csv);

  const filtered = result
    .filter((row) => row.age > 25)
    .filter((row) => row.city === "NYC");
  assertEquals(filtered.rows.length, 2, "Chained filters");
  assertEquals(filtered.rows[0].name, "John", "First match");
  assertEquals(filtered.rows[1].name, "Bob", "Second match");
});

runTest("Filter - filter with boolean fields", () => {
  const csv = `name,active
John,true
Jane,false
Bob,true`;
  const result = parseCSV(csv);

  const active = result.filter((row) => row.active === true);
  assertEquals(active.rows.length, 2, "Active users");
});

runTest("Filter - filter with index parameter", () => {
  const csv = `name
Alice
Bob
Charlie`;
  const result = parseCSV(csv);

  const filtered = result.filter((row, index) => index < 2);
  assertEquals(filtered.rows.length, 2, "First 2 rows");
  assertEquals(filtered.rows[0].name, "Alice", "First row");
  assertEquals(filtered.rows[1].name, "Bob", "Second row");
});

runTest("Filter - filter resulting in empty set", () => {
  const csv = `name,age
John,30
Jane,25`;
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.age > 100);
  assertEquals(filtered.rows.length, 0, "No rows match filter");
  assertArrayEquals(filtered.headers, result.headers, "Headers preserved");
});

// --- Aggregation: Sum ---

runTest("Aggregation: sum - numeric column", () => {
  const csv = `name,salary
John,50000
Jane,60000
Bob,55000`;
  const result = parseCSV(csv);

  const total = result.sum("salary");
  assertEquals(total, 165000, "Sum of salaries");
});

runTest("Aggregation: sum - with non-numeric values", () => {
  const csv = `item,price
Apple,5.50
Banana,text
Cherry,3.20
Date,2.99`;
  const result = parseCSV(csv);

  const total = result.sum("price");
  assertEquals(total, 11.69, "Sum ignores non-numeric");
});

runTest("Aggregation: sum - empty column", () => {
  const csv = `name,value
John,
Jane,`;
  const result = parseCSV(csv);

  const total = result.sum("value");
  assertEquals(total, 0, "Sum of empty values is 0");
});

runTest("Aggregation: sum - negative numbers", () => {
  const csv = `transaction
-100
50
-25
200`;
  const result = parseCSV(csv);

  const total = result.sum("transaction");
  assertEquals(total, 125, "Sum with negative numbers");
});

// --- Aggregation: Average ---

runTest("Aggregation: average - simple average", () => {
  const csv = `score
100
80
90`;
  const result = parseCSV(csv);

  const avg = result.average("score");
  assertEquals(avg, 90, "Average score");
});

runTest("Aggregation: average - with non-numeric values", () => {
  const csv = `value
10
text
20
30
not_a_number`;
  const result = parseCSV(csv);

  const avg = result.average("value");
  assertEquals(avg, 20, "Average (ignoring non-numeric)");
});

runTest("Aggregation: average - floating point average", () => {
  const csv = `value
5
10
15`;
  const result = parseCSV(csv);

  const avg = result.average("value");
  assertEquals(avg, 10, "Floating point average");
});

runTest("Aggregation: average - empty values", () => {
  const csv = `value
""
""`;
  const result = parseCSV(csv);

  const avg = result.average("value");
  assertEquals(avg, 0, "Average of null values is 0");
});

// --- Aggregation: Count ---

runTest("Aggregation: count - row count", () => {
  const csv = `name
John
Jane
Bob`;
  const result = parseCSV(csv);

  assertEquals(result.count(), 3, "Total row count");
});

runTest("Aggregation: count - after filtering", () => {
  const csv = `name,age
John,30
Jane,25
Bob,35`;
  const result = parseCSV(csv);

  const filtered = result.filter((row) => row.age > 25);
  assertEquals(filtered.count(), 2, "Count after filter");
});

runTest("Aggregation: count - empty result", () => {
  const csv = `name`;
  const result = parseCSV(csv);

  assertEquals(result.count(), 0, "Count of empty result");
});

// --- Aggregation: GroupBy ---

runTest("Aggregation: groupBy - simple grouping", () => {
  const csv = `name,department
John,Sales
Jane,IT
Bob,Sales
Alice,IT`;
  const result = parseCSV(csv);

  const groups = result.groupBy("department");
  assertEquals(groups.size, 2, "Two groups");
  assertEquals(groups.get("Sales")?.length, 2, "Sales group size");
  assertEquals(groups.get("IT")?.length, 2, "IT group size");
});

runTest("Aggregation: groupBy - with null values", () => {
  const csv = `item,category
Apple,Fruit
Carrot,
Banana,Fruit
Potato,
Orange,Fruit`;
  const result = parseCSV(csv);

  const groups = result.groupBy("category");
  assertEquals(groups.get("Fruit")?.length, 3, "Fruit group");
  assertEquals(groups.get(null)?.length, 2, "Null group");
});

runTest("Aggregation: groupBy - numeric grouping", () => {
  const csv = `name,score
Alice,90
Bob,85
Charlie,90
David,85
Eve,90`;
  const result = parseCSV(csv);

  const groups = result.groupBy("score");
  assertEquals(groups.size, 2, "Two score groups");
  assertEquals(groups.get("90")?.length, 3, "Score 90 group");
  assertEquals(groups.get("85")?.length, 2, "Score 85 group");
});

runTest("Aggregation: groupBy - single group", () => {
  const csv = `name,type
Alice,User
Bob,User
Charlie,User`;
  const result = parseCSV(csv);

  const groups = result.groupBy("type");
