/**
 * CSV Parser Library (JavaScript Version)
 * A comprehensive CSV parser with type coercion, error handling, and aggregation methods
 */

/**
 * Coerce a string value to its appropriate type
 */
function coerceValue(value) {
  // Handle null values
  if (value === "null" || value === "NULL" || value === "") {
    return null;
  }

  // Handle booleans
  if (value.toLowerCase() === "true") {
    return true;
  }
  if (value.toLowerCase() === "false") {
    return false;
  }

  // Handle numbers
  const trimmed = value.trim();
  if (!isNaN(Number(trimmed)) && trimmed !== "") {
    return Number(trimmed);
  }

  // Default to string
  return value;
}

/**
 * Parse a single CSV line into fields, handling quotes and escaping
 */
function parseCSVLine(line, delimiter = ",", quote = '"') {
  const fields = [];
  let currentField = "";
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    const nextChar = line[i + 1];

    if (char === quote) {
      if (inQuotes && nextChar === quote) {
        // Escaped quote (two quotes = one literal quote)
        currentField += quote;
        i += 2;
      } else {
        // Toggle quoted state
        inQuotes = !inQuotes;
        i++;
      }
    } else if (char === delimiter && !inQuotes) {
      // Field delimiter found (not inside quotes)
      fields.push(currentField);
      currentField = "";
      i++;
    } else {
      // Regular character
      currentField += char;
      i++;
    }
  }

  // Add the last field
  fields.push(currentField);

  // Check for unclosed quotes
  if (inQuotes) {
    return { fields: [], error: "Unclosed quote in CSV line" };
  }

  return { fields };
}

/**
 * Create a CSVResult object with all methods
 */
function createCSVResult(rows, headers, errors) {
  return {
    rows,
    headers,
    errors,

    filter(predicate) {
      const filtered = rows.filter(predicate);
      return createCSVResult(filtered, headers, errors);
    },

    sum(column) {
      let sum = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          sum += value;
        }
      }
      return sum;
    },

    average(column) {
      let sum = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number") {
          sum += value;
          count++;
        }
      }
      return count === 0 ? 0 : sum / count;
    },

    count() {
      return rows.length;
    },

    groupBy(column) {
      const groups = new Map();
      for (const row of rows) {
        const value = row[column];
        const key = value === null ? null : String(value);
        if (!groups.has(key)) {
          groups.set(key, []);
        }
        groups.get(key).push(row);
      }
      return groups;
    },
  };
}

/**
 * Parse CSV content into structured data
 */
function parseCSV(input, options = {}) {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? "\n";

  const errors = [];
  const rows = [];

  // Split input into lines
  const lines = input.split(lineSeparator);

  // Handle empty input
  if (lines.length === 0 || (lines.length === 1 && lines[0].trim() === "")) {
    return createCSVResult([], [], []);
  }

  // Parse header line
  const headerResult = parseCSVLine(lines[0], delimiter, quote);
  if (headerResult.error) {
    errors.push({ row: 0, message: headerResult.error });
    return createCSVResult([], [], errors);
  }

  const headers = headerResult.fields.map((h) => h.trim());

  // Parse data rows
  for (let rowIndex = 1; rowIndex < lines.length; rowIndex++) {
    const line = lines[rowIndex];

    // Skip empty lines
    if (line.trim() === "") {
      continue;
    }

    const result = parseCSVLine(line, delimiter, quote);

    if (result.error) {
      errors.push({ row: rowIndex, message: result.error });
      continue;
    }

    const fields = result.fields;

    // Validate field count
    if (fields.length !== headers.length) {
      errors.push({
        row: rowIndex,
        message: `Field count mismatch: expected ${headers.length}, got ${fields.length}`,
      });
      continue;
    }

    // Create row object with type coercion
    const row = {};
    for (let fieldIndex = 0; fieldIndex < headers.length; fieldIndex++) {
      const value = fields[fieldIndex].trim();
      row[headers[fieldIndex]] = coerceValue(value);
    }

    rows.push(row);
  }

  return createCSVResult(rows, headers, errors);
}

module.exports = { parseCSV };

