## Type Coercion

### Example 11: Automatic Type Detection
```typescript
const csv = `id,name,age,active,balance,created
1,John,30,true,100.50,2024-01-01
2,Jane,28,false,250.75,2024-01-02
3,Bob,35,true,0,null`;

const result = parseCSV(csv);

const row1 = result.rows[0];
console.log(typeof row1.id);       // "number"
console.log(typeof row1.age);      // "number"
console.log(typeof row1.active);   // "boolean"
console.log(typeof row1.balance);  // "number"
console.log(typeof row1.created);  // "string"

const row3 = result.rows[2];
console.log(row3.balance);         // 0 (number, not null)
console.log(row3.created);         // null
```

### Example 12: Mixed Type Columns
```typescript
const csv = `value
100
25.5
text
true
false
null`;

const result = parseCSV(csv);

console.log(result.rows.map(r => ({
  value: r.value,
  type: typeof r.value
})));
// Output: [
//   { value: 100, type: "number" },
//   { value: 25.5, type: "number" },
//   { value: "text", type: "string" },
//   { value: true, type: "boolean" },
//   { value: false, type: "boolean" },
//   { value: null, type: "object" }
// ]
```

### Example 13: Empty Fields and Null
```typescript
const csv = `id,name,note
1,John,
2,,empty name
3,Charlie,null`;

const result = parseCSV(csv);

console.log(result.rows[0].note);   // null (empty string)
console.log(result.rows[1].name);   // null (empty string)
console.log(result.rows[2].note);   // "null" (string, not null)
```

### Example 14: Boolean Conversion
```typescript
const csv = `active
true
True
TRUE
false
False
FALSE`;

const result = parseCSV(csv);

// All variations convert correctly
console.log(result.rows.filter(r => r.active === true).length);  // 3
console.log(result.rows.filter(r => r.active === false).length); // 3
```

---

## Error Handling

### Example 15: Check for Parsing Errors
```typescript
const csv = `name,value
"John,100
"Jane,200`;

const result = parseCSV(csv);

if (result.errors.length > 0) {
  console.log("Parsing errors found:");
  for (const error of result.errors) {
    console.log(`Row ${error.row}: ${error.message}`);
  }
}
// Output:
// Parsing errors found:
// Row 1: Unclosed quote in CSV line

console.log("Valid rows:", result.rows.length);
// Output: Valid rows: 1
```

### Example 16: Partial Data Recovery
```typescript
const csv = `id,name,age
1,John,30
2,Jane,invalid,extra
3,Bob,25`;

const result = parseCSV(csv);

console.log("Valid rows:", result.rows.length);        // 2
console.log("Errors:", result.errors.length);         // 1
console.log("Error details:", result.errors[0]);
// Output: Error details: { row: 2, message: "Field count mismatch: expected 3, got 4" }

// Still have valid data
console.log(result.rows[0].name);  // "John"
console.log(result.rows[1].name);  // "Bob"
```

### Example 17: Validation Pipeline
```typescript
const csv = `email,domain
john@example.com,
jane@invalid,incomplete
bob@test.org,valid`;

const result = parseCSV(csv);

// Filter out rows with errors
if (result.errors.length > 0) {
  console.log("Warning: Some rows failed to parse");
}

// Validate parsed data
const validRows = result.rows.filter(row => row.email && row.email.includes("@"));
console.log(`Valid emails: ${validRows.length}`);
```

---

## Filtering Data

### Example 18: Simple Filtering
```typescript
const csv = `name,age,city
John,30,NYC
Jane,25,LA
Bob,35,NYC
Alice,28,Chicago`;

const result = parseCSV(csv);

// People over 28
const over28 = result.filter(row => row.age > 28);
console.log(over28.rows);
// Output: [
//   { name: "John", age: 30, city: "NYC" },
//   { name: "Bob", age: 35, city: "NYC" }
// ]
```

### Example 19: String Filtering
```typescript
const csv = `product,category,price
Apple,Fruit,1.50
Banana,Fruit,0.80
Carrot,Vegetable,0.50
Broccoli,Vegetable,2.00`;

const result = parseCSV(csv);

// Only vegetables
const vegetables = result.filter(row => row.category === "Vegetable");
console.log(vegetables.count()); // 2

// Vegetables that cost more than $1
const expensiveVegetables = vegetables.filter(row => row.price > 1);
console.log(expensiveVegetables.count()); // 1
```

### Example 20: Chained Filters
```typescript
const csv = `name,department,salary,active
Alice,Engineering,80000,true
Bob,Sales,60000,true
Charlie,Engineering,75000,false
Diana,Sales,65000,true`;

const result = parseCSV(csv);

// Active employees in Engineering
const activeEngineers = result
  .filter(row => row.active === true)
  .filter(row => row.department === "Engineering");

console.log(activeEngineers.rows);
// Output: [
//   { name: "Alice", department: "Engineering", salary: 80000, active: true }
// ]
```

### Example 21: Index-Based Filtering
```typescript
const csv = `id,name
1,Alice
2,Bob
3,Charlie
4,Diana
5,Eve`;

const result = parseCSV(csv);

// Get first 3 rows
const firstThree = result.filter((row, index) => index < 3);
console.log(firstThree.count()); // 3

// Get every other row
const everyOther = result.filter((row, index) => index % 2 === 0);
console.log(everyOther.rows.map(r => r.name));
// Output: ["Alice", "Charlie", "Eve"]
```

---

## Aggregation Methods

### Example 22: Sum Values
```typescript
const csv = `product,sales
Widget,150
Gadget,200
Tool,100
Widget,120`;

const result = parseCSV(csv);

const totalSales = result.sum("sales");
console.log(totalSales); // 570

// Sum with filtering
const widgetSales = result
  .filter(row => row.product === "Widget")
  .sum("sales");
console.log(widgetSales); // 270
```

### Example 23: Average Values
```typescript
const csv = `student,score
Alice,95
Bob,87
Charlie,92
Diana,88
Eve,95`;

const result = parseCSV(csv);

const avgScore = result.average("score");
console.log(avgScore); // 91.4

// Average for students with score > 90
const highScorers = result.filter(row => row.score > 90);
console.log(highScorers.average("score")); // 94
```

### Example 24: Count Rows
```typescript
const csv = `id,status
1,active
2,inactive
3,active
4,active`;

const result = parseCSV(csv);

console.log(result.count()); // 4

// Count active only
const active = result.filter(row => row.status === "active");
console.log(active.count()); // 3
```

### Example 25: GroupBy Categories
```typescript
const csv = `name,department,salary
Alice,Engineering,80000
Bob,Sales,60000
Charlie,Engineering,75000
Diana,Sales,65000`;

const result = parseCSV(csv);

const byDept = result.groupBy("department");

for (const [dept, employees] of byDept) {
  console.log(`${dept}: ${employees.length} employees`);
}
// Output:
// Engineering: 2 employees
// Sales: 2 employees
```

### Example 26: GroupBy with Analysis
```typescript
const csv = `product,category,price
Apple,Fruit,1.50
Banana,Fruit,0.80
Orange,Fruit,1.20
Carrot,Vegetable,0.50
Broccoli,Vegetable,2.00`;

const result = parseCSV(csv);

const byCategory = result.groupBy("category");

// Calculate average price by category
for (const [category, items] of byCategory) {
  const sum = items.reduce((acc, item) => acc + item.price, 0);
  const avg = sum / items.length;
  console.log(`${category}: $${avg.toFixed(2)}`);
}
// Output:
// Fruit: $1.17
// Vegetable: $1.25
```

---

## Real-World Scenarios

### Example 27: Sales Report Analysis
```typescript
const csv = `date,salesperson,product,amount,region
2024-01-01,John,Widget,1000,North
2024-01-02,Jane,Gadget,1500,South
2024-01-02,John,Tool,800,North
2024-01-03,Bob,Widget,1200,East
2024-01-03,Jane,Tool,900,South`;

const result = parseCSV(csv);

// Sales by region
const byRegion = result.groupBy("region");
console.log("Sales by region:");
for (const [region, sales] of byRegion) {
  const total = sales.reduce((sum, s) => sum + s.amount, 0);
  console.log(`  ${region}: $${total}`);
}

// Top performer
const topSalesReps = result.groupBy("salesperson");
let topRep = "";
let maxSales = 0;
for (const [rep, sales] of topSalesReps) {
  const total = sales.reduce((sum, s) => sum + s.amount, 0);
  if (total > maxSales) {
    maxSales = total;
    topRep = rep;
  }
}
console.log(`Top salesperson: ${topRep} ($${maxSales})`);

// Average transaction
const avg = result.average("amount");
console.log(`Average transaction: $${avg.toFixed(2)}`);
```

### Example 28: Student Grade Analysis
```typescript
const csv = `name,math,english,science,history
Alice,95,92,94,91
Bob,78,85,80,82
Charlie,92,90,95,93
Diana,85,88,86,87
Eve,98,96,99,97`;

const result = parseCSV(csv);

// Pass/fail (average >= 80)
const grades = ["math", "english", "science", "history"];
const students = result.rows.map(student => {
  const avg = grades.reduce((sum, subject) => sum + student[subject], 0) / grades.length;
  return {
    name: student.name,
    average: avg,
    passed: avg >= 80
  };
});

students.sort((a, b) => b.average - a.average);
students.forEach(s => {
  console.log(`${s.name}: ${s.average.toFixed(1)} (${s.passed ? "PASS" : "FAIL"})`);
