```typescript
const csv = `customer,date,amount,status
John Doe,2024-01-01,150.00,completed
Jane Smith,2024-01-02,200.50,completed
John Doe,2024-01-03,75.25,completed
Bob Johnson,2024-01-04,300.00,pending
Jane Smith,2024-01-05,125.75,completed`;

