// Check for parsing errors
if (result.errors.length > 0) {
  console.log("⚠️ Found issues:");
  result.errors.forEach(e => console.log(`  Row ${e.row}: ${e.message}`));
}

// Clean and validate
const cleanData = result
  .filter(row => row.email) // Remove rows with empty email
  .rows
  .map(row => ({
    ...row,
    email: row.email.toLowerCase(),
    emailValid: row.email.includes("@"),
    hasSignupDate: row.signup_date !== null
  }));

console.log("\n✓ Valid records:", cleanData.filter(r => r.emailValid).length);
console.log("⚠️ Invalid records:", cleanData.filter(r => !r.emailValid).length);
